import React, { useState } from 'react';
import { Link } from 'gatsby';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { useResolved, ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import '../global.css';

// Base URL where the music images live on the server
const MUSIC_CDN = 'https://bodephatquoc.org/wp-content/uploads/bdpq/music/';

const MusicPageInner = () => {
  const resolved = useResolved();
  const musicData = resolved.pages.musicPage;
  const albums = musicData.albums || [];

  const [visibleCount, setVisibleCount] = useState(24);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAlbum, setSelectedAlbum] = useState<string>('all');

  // Handle hash navigation
  React.useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash) {
        const mapping: {[key:string]: string} = {
          '#cd-phat-su': 'CD Phật Sự',
          '#bo-de': 'Bồ Đề Phật Quốc',
          '#phat-dieu': 'Phật Diệu'
        };
        const searchVal = mapping[hash.toLowerCase()];
        if (searchVal) {
          // Look for an album id that matches the name
          const found = albums.find((a: any) => (a.name || '').includes(searchVal));
          if (found) {
            setSelectedAlbum(found.id);
            // Scroll to grid
            const grid = document.querySelector('.music-grid');
            if (grid) grid.scrollIntoView({ behavior: 'smooth', block: 'start' });
          } else {
            setSearchQuery(searchVal);
          }
        }
      }
    };
    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [albums]);

  // Flatten all tracks from albums that have tracks
  const allTracks = albums
    .filter((album: any) => album.tracks && album.tracks.length > 0)
    .flatMap((album: any) =>
      album.tracks.map((track: any) => ({
        ...track,
        albumName: album.name,
        albumId: album.id,
        // resolve image: prefer track.image if it's a full URL, otherwise
        // try imageFile as path under MUSIC_CDN, fall back to null
        resolvedImage: track.image
          ? track.image
          : track.imageFile
          ? `${MUSIC_CDN}${track.imageFile}`
          : null,
      }))
    );

  // Albums that actually have tracks (for filter tabs)
  const activeAlbums = albums.filter(
    (album: any) => album.tracks && album.tracks.length > 0
  );

  // Filter by search + selected album
  const filteredTracks = allTracks.filter((track: any) => {
    const matchesAlbum =
      selectedAlbum === 'all' || track.albumId === selectedAlbum;
    if (!searchQuery) return matchesAlbum;
    const q = searchQuery.toLowerCase();
    return (
      matchesAlbum &&
      ((track.title || '').toLowerCase().includes(q) ||
        (track.singer || '').toLowerCase().includes(q) ||
        (track.category || '').toLowerCase().includes(q))
    );
  });

  const displayedTracks = filteredTracks.slice(0, visibleCount);

  return (
    <div className="music-page">
      <Header />
      <div style={{ height: '60px' }} />

      <main className="music-container">
        <header className="music-header">
          <h1>{musicData.sectionTitle || 'Thư viện Âm nhạc'}</h1>

          {/* Search */}
          <div className="music-search-bar">
            <input
              type="text"
              placeholder="Tìm kiếm bài hát, ca sĩ..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setVisibleCount(24);
              }}
              className="music-search-input"
            />
          </div>
        </header>

        {/* Album filter tabs */}
        <div className="album-tabs">
          <button
            className={`album-tab ${selectedAlbum === 'all' ? 'active' : ''}`}
            onClick={() => { setSelectedAlbum('all'); setVisibleCount(24); }}
          >
            Tất cả
          </button>
          {activeAlbums.map((album: any) => (
            <button
              key={album.id}
              className={`album-tab ${selectedAlbum === album.id ? 'active' : ''}`}
              onClick={() => { setSelectedAlbum(album.id); setVisibleCount(24); }}
            >
              {album.name}
            </button>
          ))}
        </div>

        {/* Tracks grid */}
        {displayedTracks.length === 0 ? (
          <div className="music-empty">
            <span>🎵</span>
            <p>Không tìm thấy bài hát phù hợp.</p>
          </div>
        ) : (
          <div className="music-grid">
            {displayedTracks.map((track: any) => {
              const isExternal = track.slug?.startsWith('http');
              const linkTo = isExternal
                ? track.slug
                : (track.slug || track.id) 
                  ? `https://bodephatquoc.org/wp-content/music/${track.slug || track.id}`
                  : null;

              const card = (
                <div className="music-card">
                  <div className="music-thumb">
                    {track.resolvedImage ? (
                      <img
                        src={track.resolvedImage}
                        alt={track.title}
                        onError={(e) => {
                          e.currentTarget.style.display = 'none';
                          const placeholder = e.currentTarget.nextElementSibling as HTMLElement;
                          if (placeholder) placeholder.style.display = 'flex';
                        }}
                      />
                    ) : null}
                    <div
                      className="music-img-fallback"
                      style={{ display: track.resolvedImage ? 'none' : 'flex' }}
                    >
                      🎵
                    </div>
                    <div className="music-play-icon">▶</div>
                  </div>
                  <div className="music-info">
                    <p className="music-album-label">{track.category || track.albumName}</p>
                    <h3 className="music-title">{track.title}</h3>
                    {track.singer && (
                      <p className="music-singer">{track.singer}</p>
                    )}
                  </div>
                </div>
              );

              if (!linkTo) {
                return (
                  <div key={track.id} className="music-card-link no-link">
                    {card}
                  </div>
                );
              }

              return isExternal ? (
                <a
                  key={track.id}
                  href={linkTo}
                  className="music-card-link"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  {card}
                </a>
              ) : (
                <Link key={track.id} to={linkTo} target="_blank" rel="noopener noreferrer" className="music-card-link">
                  {card}
                </Link>
              );
            })}
          </div>
        )}

        {visibleCount < filteredTracks.length && (
          <div className="music-load-more">
            <button
              className="load-more-btn"
              onClick={() => setVisibleCount((p) => p + 24)}
            >
              Xem thêm bài hát
            </button>
          </div>
        )}
      </main>

      <Footer />

      <style dangerouslySetInnerHTML={{
        __html: `
        .music-page {
          background-color: #f5f3ee;
          min-height: 100vh;
        }
        .music-container {
          max-width: 1200px;
          margin: 0 auto;
          padding: 40px 20px 80px;
        }
        .music-header {
          margin-bottom: 32px;
          border-bottom: 2px solid #E6B422;
          padding-bottom: 20px;
          display: flex;
          justify-content: space-between;
          align-items: center;
          flex-wrap: wrap;
          gap: 16px;
        }
        .music-header h1 {
          font-family: 'Playfair Display', serif;
          color: #1a1a1a;
          margin: 0;
          font-size: 28px;
        }
        .music-search-bar {
          flex: 1;
          max-width: 360px;
          min-width: 220px;
          display: flex;
          justify-content: flex-end;
        }
        .music-search-input {
          width: 100%;
          padding: 10px 18px;
          border-radius: 30px;
          border: 1px solid rgba(0,0,0,0.12);
          background: #fff;
          font-family: 'Inter', sans-serif;
          font-size: 14px;
          transition: all 0.3s ease;
        }
        .music-search-input:focus {
          outline: none;
          border-color: #E6B422;
          box-shadow: 0 0 0 3px rgba(230,180,34,0.2);
        }
        /* Album tabs */
        .album-tabs {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
          margin-bottom: 32px;
        }
        .album-tab {
          padding: 7px 16px;
          border-radius: 20px;
          border: 1.5px solid #E6B422;
          background: transparent;
          color: #555;
          font-size: 13px;
          font-family: 'Inter', sans-serif;
          cursor: pointer;
          transition: all 0.2s ease;
          white-space: nowrap;
        }
        .album-tab:hover {
          background: rgba(230,180,34,0.12);
          color: #1a1a1a;
        }
        .album-tab.active {
          background: #E6B422;
          color: #fff;
          border-color: #E6B422;
          font-weight: 600;
        }
        /* Grid */
        .music-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
          gap: 24px;
        }
        .music-card-link {
          text-decoration: none;
          color: inherit;
          display: block;
        }
        .music-card {
          background: #fff;
          border-radius: 12px;
          overflow: hidden;
          box-shadow: 0 3px 12px rgba(0,0,0,0.06);
          transition: transform 0.3s ease, box-shadow 0.3s ease;
        }
        .music-card:hover {
          transform: translateY(-6px);
          box-shadow: 0 10px 28px rgba(0,0,0,0.10);
        }
        .music-thumb {
          aspect-ratio: 1/1;
          background: #f0ece4;
          position: relative;
          overflow: hidden;
        }
        .music-thumb img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.5s ease;
          display: block;
        }
        .music-card:hover .music-thumb img {
          transform: scale(1.06);
        }
        .music-img-fallback {
          width: 100%;
          height: 100%;
          align-items: center;
          justify-content: center;
          font-size: 52px;
          color: #c5b38a;
          background: linear-gradient(135deg, #f5f0e6 0%, #e8dfc9 100%);
        }
        .music-play-icon {
          position: absolute;
          bottom: 10px;
          right: 10px;
          width: 36px;
          height: 36px;
          background: rgba(230,180,34,0.88);
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          color: #fff;
          font-size: 13px;
          opacity: 0;
          transition: opacity 0.25s ease;
          padding-left: 2px;
        }
        .music-card:hover .music-play-icon {
          opacity: 1;
        }
        .music-info {
          padding: 14px 16px 16px;
        }
        .music-album-label {
          margin: 0 0 5px 0;
          font-size: 11px;
          color: #E6B422;
          font-weight: 700;
          letter-spacing: 1px;
          text-transform: uppercase;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        .music-title {
          margin: 0 0 4px 0;
          font-size: 15px;
          color: #1a1a1a;
          font-family: 'Playfair Display', serif;
          line-height: 1.35;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }
        .music-singer {
          margin: 0;
          font-size: 12px;
          color: #888;
          font-style: italic;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        /* Empty state */
        .music-empty {
          text-align: center;
          padding: 80px 20px;
          color: #aaa;
        }
        .music-empty span {
          font-size: 60px;
          display: block;
          margin-bottom: 16px;
        }
        .music-empty p {
          font-size: 18px;
          font-family: 'Inter', sans-serif;
        }
        /* Load more */
        .music-load-more {
          display: flex;
          justify-content: center;
          margin-top: 48px;
        }
        .load-more-btn {
          background-color: #E6B422;
          color: white;
          border: none;
          padding: 13px 40px;
          border-radius: 30px;
          font-size: 15px;
          font-weight: 600;
          font-family: 'Inter', sans-serif;
          cursor: pointer;
          transition: all 0.3s ease;
          box-shadow: 0 4px 15px rgba(230,180,34,0.3);
        }
        .load-more-btn:hover {
          background-color: #d4a31d;
          transform: translateY(-2px);
          box-shadow: 0 6px 20px rgba(230,180,34,0.4);
        }
        @media (max-width: 768px) {
          .music-header {
            flex-direction: column;
            align-items: flex-start;
          }
          .music-search-bar {
            max-width: 100%;
            width: 100%;
            justify-content: flex-start;
          }
          .music-search-input {
            width: 100%;
          }
          .music-grid {
            grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
            gap: 16px;
          }
        }
      `}} />
    </div>
  );
};

const MusicPage = () => (
  <ResolvedContentProvider>
    <MusicPageInner />
  </ResolvedContentProvider>
);

export default MusicPage;
